// ═══════════════════════════════════════════════════════════════════════════
// TESTING AGENT v1.4 — Node A: Health Checks + Signal Fire
// Runs T6 (workflow health) + T7 (webhook latency) + fires T1–T5 test signals
// Outputs timestamps + T6/T7 results to Node B for polling
// Split design: each node gets its own 60s execution window
// ═══════════════════════════════════════════════════════════════════════════

const WEBHOOK    = 'https://tradenextgen.app.n8n.cloud/webhook/tradingview-signal';
const N8N_API    = 'https://tradenextgen.app.n8n.cloud/api/v1';
const N8N_KEY    = 'REDACTED_JWT_TOKEN';
const MAIN_WF_ID = 'vaqfCaELhOEWnkdo';
const _WEBHOOK_SECRET = ($getWorkflowStaticData('global')._credentials || {}).webhook_secret || '';


const TICKERS = { T1:'TSMFP', T2:'TSKLL', T3:'TSSCN', T4:'TSSTA', T5:'TSSHD' };

const KEY_WORKFLOWS = {
  'Main Pipeline':     MAIN_WF_ID,
  'Broad Scanner':     '975pZZEtxeUbzI22',
  'Polygon Sentiment': 'ARfeHFGyGQGgeXXB',
  'Daily P&L Report':  'C7UU7yAs2DgaRhqi',
};

function check(name, pass, detail) { return { name, pass, detail: String(detail || '') }; }

const nowET   = new Date().toLocaleString('en-US', { timeZone: 'America/New_York' });
const runDate = new Date().toLocaleDateString('en-US', { timeZone: 'America/New_York' });
console.log('[NODE A] Starting at', nowET);

// ── T6: Workflow Health ──────────────────────────────────────────────────────
let t6Checks = [];
try {
  const wfResults = await Promise.all(
    Object.entries(KEY_WORKFLOWS).map(([label, wfId]) =>
      this.helpers.httpRequest({
        method: 'GET', url: `${N8N_API}/workflows/${wfId}`,
        headers: { 'X-N8N-API-KEY': N8N_KEY }, json: true
      }).then(wf => check(label + ' active', wf.active === true, `active=${wf.active}`))
       .catch(e => check(label + ' active', false, String(e.message).slice(0, 60)))
    )
  );
  t6Checks.push(...wfResults);
  const bsExec = await this.helpers.httpRequest({
    method: 'GET',
    url: `${N8N_API}/executions?workflowId=975pZZEtxeUbzI22&limit=1`,
    headers: { 'X-N8N-API-KEY': N8N_KEY }, json: true
  });
  const lastBsMs  = new Date(bsExec.data?.[0]?.startedAt || 0).getTime();
  const bsAgeMins = ((Date.now() - lastBsMs) / 60000).toFixed(0);
  t6Checks.push(check('Broad Scanner recent (<15m)', bsAgeMins < 15, `last run ${bsAgeMins}m ago`));
} catch (e) {
  t6Checks.push(check('API health check', false, String(e.message).slice(0, 60)));
}
const t6Pass = t6Checks.every(c => c.pass);
const t6Result = {
  id: 'T6', name: 'Workflow Health Check',
  status: t6Pass ? 'PASS' : t6Checks.some(c => c.pass) ? 'WARN' : 'FAIL',
  checks: t6Checks, note: '',
};
console.log('[T6] Workflow Health:', t6Pass ? 'PASS' : 'ISSUES');

// ── T7: Webhook Latency ──────────────────────────────────────────────────────
let t7Checks = [];
try {
  const t7Start = Date.now();
  const t7Resp = await this.helpers.httpRequest({
    method: 'POST', url: WEBHOOK,
    body: {
      _secret: _WEBHOOK_SECRET,
      ticker: 'TWTEST', price: '100.00', execution: 'STAND ASIDE',
      signal: 'NEUTRAL', bias_score: '0', smart_money: 'NEUTRAL',
      liquidity: 'NONE', fvg: 'NONE', order_block: 'NONE',
      vix: '20', vol_adx: '0.5/30', total_pen: '10', vol_pen: '5',
      regime_pen: '0', ob_pen: '0', vix_vwap: '0', loc_pen: '0',
      test: true
    },
    json: true,
  });
  const t7Ms = Date.now() - t7Start;
  t7Checks.push(check('Webhook responds < 3s', t7Ms < 3000, `${t7Ms}ms`));
  t7Checks.push(check('HTTP 200 received', !!t7Resp, t7Resp ? 'OK' : 'no response'));
} catch (e) {
  t7Checks.push(check('Webhook reachable', false, String(e.message || e).slice(0, 80)));
}
const t7Pass = t7Checks.every(c => c.pass);
const t7Result = {
  id: 'T7', name: 'Webhook Latency (TradingView Compatibility)',
  status: t7Pass ? 'PASS' : 'FAIL',
  checks: t7Checks,
  note: t7Pass ? 'onReceived mode OK' : 'CRITICAL: TradingView will timeout!',
};
console.log('[T7] Webhook Latency:', t7Pass ? 'PASS' : 'FAIL', t7Checks[0]?.detail || '');

// ── Fire T1–T5 signals ───────────────────────────────────────────────────────
async function fire(payload) {
  const sentAt = Date.now();
  await this.helpers.httpRequest({
    method: 'POST', url: WEBHOOK,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ _secret: _WEBHOOK_SECRET, ...payload, test_mode: true, _is_test: true }),
    json: false
  });
  return sentAt;
}

const T1_PAYLOAD = {
  ticker: TICKERS.T1, execution: 'BUY', signal: 'BULLISH',
  alert_type: 'STRONG_SETUP', price: '210.00', timeframe: 'D',
  bias_score:'71', bull_score:'76', bear_score:'24', adx:'28.5',
  rsi:'56', vix:'17.0', regime:'TRENDING',
  strat_total_trades:'42', strat_profit_factor:'2.95',
  strat_win_rate:'65.0', strat_net_pct:'18.2',
  volume_ratio:'1.5', atr:'3.10',
  spy_status:'BULLISH', daily_trend:'UP', cross_asset_status:'RISK_ON',
};
const T2_PAYLOAD = {
  ticker: TICKERS.T2, execution: 'BUY', signal: 'BULLISH',
  alert_type: 'STRONG_SETUP', price: '145.00', timeframe: 'D',
  bias_score:'67', bull_score:'70', bear_score:'30', adx:'8.0',
  rsi:'55', vix:'18.0', regime:'NEUTRAL',
  strat_total_trades:'35', strat_profit_factor:'2.10', strat_win_rate:'60.0',
  volume_ratio:'1.2', atr:'2.50',
};
const T3_PAYLOAD = {
  ticker: TICKERS.T3, execution: 'BUY', signal: 'BULLISH',
  alert_type: 'BROAD_SCANNER', price: '175.00', timeframe: 'D',
  bias_score:'65', bull_score:'68', bear_score:'32', adx:'N/A',
  rsi:'57', vix:'17.5', regime:'TRENDING',
  strat_total_trades:'0', strat_profit_factor:'0',
  volume_ratio:'1.3', atr:'2.80',
};
const T4_PAYLOAD = {
  ticker: TICKERS.T4, execution: 'STAND ASIDE', signal: 'NEUTRAL',
  alert_type: 'SIGNAL_CHANGE', price: '180.00', timeframe: 'D',
  bias_score:'50', bull_score:'49', bear_score:'51', adx:'N/A',
  rsi:'50', vix:'18.0', regime:'NEUTRAL', volume_ratio:'1.0', atr:'2.80',
};
const T5_PAYLOAD = {
  ticker: TICKERS.T5, execution: 'SELL', signal: 'BEARISH',
  alert_type: 'STRONG_SETUP', price: '88.50', timeframe: 'D',
  bias_score:'32', bull_score:'26', bear_score:'74', adx:'27.0',
  rsi:'43', vix:'17.5', regime:'TRENDING',
  strat_total_trades:'38', strat_profit_factor:'3.80',
  strat_win_rate:'65.0', strat_net_pct:'21.2',
  volume_ratio:'1.7', atr:'2.10',
  spy_status:'BEARISH', daily_trend:'DOWN', cross_asset_status:'RISK_OFF',
};

console.log('[NODE A] Firing 5 test signals in parallel...');
const [t1Sent, t2Sent, t3Sent, t4Sent, t5Sent] = await Promise.all([
  fire.call(this, T1_PAYLOAD),
  fire.call(this, T2_PAYLOAD),
  fire.call(this, T3_PAYLOAD),
  fire.call(this, T4_PAYLOAD),
  fire.call(this, T5_PAYLOAD),
]);
console.log('[NODE A] All signals fired. Passing timestamps to Node B.');

return [{ json: {
  t1Sent, t2Sent, t3Sent, t4Sent, t5Sent,
  t6Result, t7Result,
  runDate, runTime: nowET,
  tickers: TICKERS,
  mainWfId: MAIN_WF_ID,
}}];

// ═══════════════════════════════════════════════════════════════════════════
// TESTING AGENT v1.4 — Node B: Poll + Evaluate T1–T5
// Receives fired timestamps from Node A, polls n8n for executions,
// evaluates all 5 tests and builds final report
// ═══════════════════════════════════════════════════════════════════════════

const N8N_API    = 'https://tradenextgen.app.n8n.cloud/api/v1';
const N8N_KEY    = 'REDACTED_JWT_TOKEN';

// Read inputs from Node A
const prev      = $input.first().json;
const { t1Sent, t2Sent, t3Sent, t4Sent, t5Sent,
        t6Result, t7Result, runDate, runTime,
        tickers, mainWfId } = prev;

function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }
function check(name, pass, detail) { return { name, pass, detail: String(detail || '') }; }

// ── findExec: poll n8n for execution matching test ticker ────────────────────
async function findExec(afterMs, ticker, timeoutMs) {
  const deadline = Date.now() + timeoutMs;
  while (Date.now() < deadline) {
    await sleep(3000);
    try {
      const resp = await this.helpers.httpRequest({
        method: 'GET',
        url: `${N8N_API}/executions?workflowId=${mainWfId}&limit=12&includeData=true`,
        headers: { 'X-N8N-API-KEY': N8N_KEY },
        json: true
      });
      for (const e of (resp.data || [])) {
        if (new Date(e.startedAt).getTime() < afterMs - 3000) continue;
        const runData = e.data?.resultData?.runData || {};
        const whItems = (runData['Webhook Trigger']?.[0]?.data?.main?.[0] || []);
        const body    = whItems[0]?.json?.body || {};
        if (body.ticker === ticker && body._is_test === true) {
          return { found: true, status: e.status, runData };
        }
      }
    } catch (_) {}
  }
  return { found: false };
}

// ── extract: pull key fields from a found execution ──────────────────────────
function extract(runData) {
  const get = (node) => (runData[node]?.[0]?.data?.main?.[0] || []);
  const smJ  = get('Signal State Machine')[0]?.json || {};
  const vcJ  = get('VC Score Parser')[0]?.json      || {};
  const slJ  = get('Shadow Logger')[0]?.json        || {};
  const ssRun= runData['Append Shadow to Sheet'];
  const ffRun= runData['Format Fast Alert'];
  return {
    sm_route:        smJ._sm_route   || null,
    sm_action:       smJ._sm_action  || null,
    sm_reason:      (smJ._sm_reason  || '').slice(0, 80),
    sm_conf:         smJ._sm_max_confidence || 0,
    vc_score:        vcJ._vc_score   || null,
    vc_verdict:      vcJ._vc_verdict || null,
    shadow_id:       slJ.Shadow_ID   || null,
    shadow_price:    slJ.Price       || null,
    shadow_exec:     slJ.Actual_Execution || null,
    sheet_ok:        !!(ssRun && (ssRun[0]?.data?.main?.[0] || []).length > 0 && !ssRun[0]?.error),
    format_fast_ran: !!(ffRun && (ffRun[0]?.data?.main?.[0] || []).length > 0),
    channel_fired:   !!(runData['Send to Channel']?.[0]?.data?.main?.[0] || []).length,
  };
}

console.log('[NODE B] Starting poll. Waiting 8s for pipeline to process signals...');
await sleep(8000);

// Poll all 5 in parallel — 30s timeout each (plenty within 60s node budget)
console.log('[NODE B] Polling for T1–T5 executions...');
const [t1r, t2r, t3r, t4r, t5r] = await Promise.all([
  findExec.call(this, t1Sent, tickers.T1, 30000),
  findExec.call(this, t2Sent, tickers.T2, 30000),
  findExec.call(this, t3Sent, tickers.T3, 30000),
  findExec.call(this, t4Sent, tickers.T4, 30000),
  findExec.call(this, t5Sent, tickers.T5, 30000),
]);

const results = [t6Result, t7Result];

// ── T1: Full Path ─────────────────────────────────────────────────────────────
{
  const d = t1r.found ? extract(t1r.runData) : {};
  const checks = [
    check('Execution found',  t1r.found,             t1r.found ? 'OK' : 'timeout'),
    check('SM route = FULL',  d.sm_route === 'FULL', `route=${d.sm_route}`),
    check('VC Gate scored',   !!d.vc_score,          `vc_score=${d.vc_score}`),
    check('Channel blocked', !d.channel_fired,       'test_mode suppressed'),
  ];
  const pass = checks.filter(c=>c.pass).length;
  results.push({ id:'T1', name:'Full Signal Path (SM→FULL→VC)', status:pass===checks.length?'PASS':pass>=2?'WARN':'FAIL', checks, note:d.sm_reason||'' });
  console.log('[T1]', results.at(-1).status, 'route='+d.sm_route, 'vc='+d.vc_score);
}

// ── T2: Kill Switch ───────────────────────────────────────────────────────────
{
  const d = t2r.found ? extract(t2r.runData) : {};
  const checks = [
    check('Execution found',       t2r.found,                  t2r.found?'OK':'timeout'),
    check('SM route = FAST_ONLY',  d.sm_route==='FAST_ONLY',   `route=${d.sm_route}`),
    check('VC Gate NOT reached',  !d.vc_score,                 `vc_score=${d.vc_score}`),
  ];
  const pass = checks.filter(c=>c.pass).length;
  results.push({ id:'T2', name:'Kill Switch — Low ADX (FAST_ONLY)', status:pass===checks.length?'PASS':pass>=2?'WARN':'FAIL', checks, note:d.sm_reason||'' });
  console.log('[T2]', results.at(-1).status, 'route='+d.sm_route);
}

// ── T3: BROAD_SCANNER Bypass ──────────────────────────────────────────────────
{
  const d = t3r.found ? extract(t3r.runData) : {};
  const checks = [
    check('Execution found',     t3r.found,             t3r.found?'OK':'timeout'),
    check('KS1 bypassed (FULL)', d.sm_route==='FULL',   `route=${d.sm_route}`),
    check('VC Gate reached',     !!d.vc_score,          `vc_score=${d.vc_score}`),
  ];
  const pass = checks.filter(c=>c.pass).length;
  results.push({ id:'T3', name:'BROAD_SCANNER Bypass (0 backtest trades)', status:pass===checks.length?'PASS':pass>=2?'WARN':'FAIL', checks, note:'' });
  console.log('[T3]', results.at(-1).status, 'route='+d.sm_route);
}

// ── T4: STAND ASIDE ───────────────────────────────────────────────────────────
{
  const d = t4r.found ? extract(t4r.runData) : {};
  const checks = [
    check('Execution found',         t4r.found,            t4r.found?'OK':'timeout'),
    check('Format Fast Alert fired', d.format_fast_ran,    d.format_fast_ran?'fired':'not fired'),
    check('VC Gate NOT reached',    !d.vc_score,           `vc_score=${d.vc_score}`),
    check('Channel blocked',        !d.channel_fired,      'test_mode suppressed'),
  ];
  const pass = checks.filter(c=>c.pass).length;
  results.push({ id:'T4', name:'STAND ASIDE Exit Path', status:pass===checks.length?'PASS':pass>=3?'WARN':'FAIL', checks, note:'' });
  console.log('[T4]', results.at(-1).status, 'fast_alert='+d.format_fast_ran);
}

// ── T5: Shadow Logger Write ───────────────────────────────────────────────────
{
  const d = t5r.found ? extract(t5r.runData) : {};
  const checks = [
    check('Execution found',   t5r.found,                                                      t5r.found?'OK':'timeout'),
    check('Shadow_ID written', !!d.shadow_id,                                                  `id=${d.shadow_id}`),
    check('Price populated',   d.shadow_price===88.5||d.shadow_price==88.5||String(d.shadow_price)==='88.5', `price=${d.shadow_price}`),
    check('Execution correct', d.shadow_exec==='SELL',                                         `exec=${d.shadow_exec}`),
    check('Sheet append OK',   d.sheet_ok,                                                     d.sheet_ok?'OK':'failed'),
  ];
  const pass = checks.filter(c=>c.pass).length;
  results.push({ id:'T5', name:'Shadow Logger Write to Sheet', status:pass===checks.length?'PASS':pass>=3?'WARN':'FAIL', checks, note:'' });
  console.log('[T5]', results.at(-1).status, 'shadow_id='+d.shadow_id, 'sheet='+d.sheet_ok);
}

// ── Summary ───────────────────────────────────────────────────────────────────
const passCount = results.filter(r=>r.status==='PASS').length;
const warnCount = results.filter(r=>r.status==='WARN').length;
const failCount = results.filter(r=>r.status==='FAIL').length;
const score = Math.round(((passCount + warnCount*0.5) / results.length) * 10 * 10) / 10;

console.log(`[NODE B] Done: ${passCount} PASS, ${warnCount} WARN, ${failCount} FAIL | Score: ${score}/10`);

return [{ json: {
  run_date: runDate,
  run_time: runTime,
  results,
  summary: { pass: passCount, warn: warnCount, fail: failCount, total: results.length, score },
}}];

// ════════════════════════════════════════════════════════════════════════════
// DAILY HEALTH REPORT FORMATTER v1.1
// ════════════════════════════════════════════════════════════════════════════
// Converts Testing Agent output into a clean Telegram message.
// Sends ONLY to personal chat. Never sends to channel.
// Mode: runOnceForEachItem
// ════════════════════════════════════════════════════════════════════════════

const BOT  = 'REDACTED_TELEGRAM_BOT_TOKEN';
const CHAT = 'REDACTED_CHAT_ID';
const NL   = '\n';

const d     = $input.item.json;
const score = d.summary.score;
const { pass, warn, fail, total } = d.summary;

// ── Grade + readiness ─────────────────────────────────────────────────────
function grade(s) {
  if (s >= 9.5) return 'A+';
  if (s >= 9.0) return 'A';
  if (s >= 8.0) return 'B';
  if (s >= 7.0) return 'C';
  if (s >= 6.0) return 'D';
  return 'F';
}
function readiness(s, failCount) {
  if (failCount === 0 && s >= 8.0) return 'READY TO TRADE';
  if (failCount <= 1 || s >= 7.0)  return 'CONDITIONAL — monitor closely';
  return 'HOLD — fix blockers before trading';
}

// ── Status icons (plain text — max Telegram compatibility) ───────────────
function icon(status) {
  return status === 'PASS' ? '[PASS]' : status === 'WARN' ? '[WARN]' : '[FAIL]';
}

// ── Build message ─────────────────────────────────────────────────────────
let msg = '';

// Header
msg += `<b>Daily Health Report — ${d.run_date}</b>` + NL;
msg += `Time: ${d.run_time}` + NL;
msg += NL;

// Score block
msg += `<b>Score: ${score}/10  |  Grade: ${grade(score)}</b>` + NL;
msg += `<b>Status: ${readiness(score, fail)}</b>` + NL;
msg += NL;

// Test results
msg += `<b>Test Results (${pass}/${total} passed):</b>` + NL;
for (const r of d.results) {
  const statusStr = icon(r.status);
  msg += `${statusStr} ${r.id}: ${r.name}` + NL;
  // Show first failed check as the detail
  const firstFail = r.checks.find(c => !c.pass);
  if (firstFail && r.status !== 'PASS') {
    msg += `       Issue: ${firstFail.name} — ${firstFail.detail}` + NL;
  }
}
msg += NL;

// Blockers section (only if any failures)
const blockers = d.results.filter(r => r.status === 'FAIL');
if (blockers.length > 0) {
  msg += `<b>Blockers (${blockers.length}):</b>` + NL;
  for (const b of blockers) {
    const failedChecks = b.checks.filter(c => !c.pass).map(c => c.name).join(', ');
    msg += `  [!] ${b.id} ${b.name}` + NL;
    msg += `      Failed: ${failedChecks}` + NL;
  }
  msg += NL;
}

// Warnings
const warnings = d.results.filter(r => r.status === 'WARN');
if (warnings.length > 0) {
  msg += `<b>Warnings:</b>` + NL;
  for (const w of warnings) {
    const failedChecks = w.checks.filter(c => !c.pass).map(c => c.name).join(', ');
    msg += `  [-] ${w.id}: ${failedChecks}` + NL;
  }
  msg += NL;
}

// Quick checklist
msg += `<b>Pre-Trade Checklist:</b>` + NL;
const t6 = d.results.find(r => r.id === 'T6');
if (t6) {
  for (const c of t6.checks) {
    msg += `  ${c.pass ? '[OK]' : '[!!]'} ${c.name}` + NL;
  }
}
msg += NL;

// Summary line
if (fail === 0 && warn === 0) {
  msg += `All systems operational. Safe to auto-trade.`;
} else if (fail === 0) {
  msg += `${warn} warning(s) — auto-trade with monitoring.`;
} else {
  msg += `${fail} blocker(s) found. Review before enabling auto-trade.`;
}

// ── Send to personal Telegram ─────────────────────────────────────────────
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `https://api.telegram.org/bot${BOT}/sendMessage`,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ chat_id: CHAT, text: msg, parse_mode: 'HTML' }),
    json: false
  });
  console.log('[HEALTH REPORT] Sent to Telegram:', score + '/10', grade(score));
} catch (e) {
  console.log('[HEALTH REPORT] Telegram error:', e.message);
}

return { json: {
  sent: true, run_date: d.run_date, score, grade: grade(score),
  readiness: readiness(score, fail),
  pass, warn, fail,
}};
